// Clean HTML: strip non-content elements, extract text
const html = $input.first().json.data || $input.first().json.body || String($input.first().json);

if (!html || typeof html !== 'string' || html.length < 100) {
  return [{
    json: {
      cleaned: false,
      error: 'Page content is too short or empty. The site may require JavaScript to load, or blocks automated access.'
    }
  }];
}

// Remove script, style, nav, footer, header, aside tags and their content
let cleaned = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '')
  .replace(/<form[^>]*>[\s\S]*?<\/form>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '');

// Convert common HTML elements to text-friendly format
cleaned = cleaned
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<\/div>/gi, '\n')
  .replace(/<\/li>/gi, '\n')
  .replace(/<\/h[1-6]>/gi, '\n\n')
  .replace(/<[^>]+>/g, ' ')  // Remove remaining HTML tags
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\n{3,}/g, '\n\n')  // Collapse multiple newlines
  .replace(/[ \t]{2,}/g, ' ')  // Collapse multiple spaces
  .trim();

// Truncate to 10,000 chars to stay within Claude context limits
if (cleaned.length > 10000) {
  cleaned = cleaned.substring(0, 10000) + '\n[... truncated]';
}

const webhookData = $('Webhook: Receive URL').first().json;

return [{
  json: {
    cleaned: true,
    text: cleaned,
    url: webhookData.body.url,
    household_id: webhookData.body.household_id
  }
}];

// Build ingredient reference list AND pre-build the Claude API request body
const ingredients = $input.all().map(item => item.json);

let referenceList = '';
for (const ing of ingredients) {
  let line = ing.name;
  if (ing.aliases && ing.aliases.length > 0) {
    line += ` (${ing.aliases.join(', ')})`;
  }
  referenceList += line + '\n';
}

const cleanedData = $('Clean HTML → Extract Text').first().json;
const recipeText = cleanedData.text;

const systemPrompt = 'You are a recipe parsing assistant for Plateful, a meal planning app. Parse the given recipe text into structured JSON. The text was extracted from a web page and may contain navigation text, ads, or other non-recipe content — ignore those and focus on the recipe. Return ONLY valid JSON, no markdown, no explanation, no code fences. Follow the exact schema specified. Always return quantities as numbers and units as strings — never some, to taste, or as needed. Match ingredient names against the provided known ingredients list when possible.';

const userMessage = 'Parse this recipe into structured JSON.\n\n## Known Ingredients (match against these):\n' + referenceList + '\n## Recipe Text (extracted from web page — ignore ads/navigation):\n' + recipeText + '\n\n## Required JSON Schema:\n{\n  "success": true,\n  "recipe": { "title": "string", "description": "string|null", "cuisine": "string|null", "meal_types": ["array"], "servings": "int", "prep_time_min": "int|null", "cook_time_min": "int|null", "difficulty": "easy|medium|hard", "tags": ["array"], "is_vegetarian": "bool", "is_vegan": "bool", "is_batch_friendly": "bool", "leftover_days": "int 0-5" },\n  "ingredients": [{ "name": "string", "matched_name": "string|null", "quantity": "number", "unit": "string", "preparation": "string|null", "is_optional": "bool", "group_name": "string|null", "sort_order": "int" }],\n  "steps": [{ "step_number": "int", "instruction": "string", "duration_min": "int|null" }]\n}\n\nIf you cannot identify a recipe, return: { "success": false, "error": "explanation" }';

const claudeBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  temperature: 0,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
};

return [{
  json: {
    recipe_text: recipeText,
    household_id: cleanedData.household_id,
    source_url: cleanedData.url,
    ingredient_reference: referenceList,
    ingredient_count: ingredients.length,
    claude_body: JSON.stringify(claudeBody)
  }
}];

// Extract and validate Claude's response
const claudeResponse = $input.first().json;
const buildData = $('Build Ingredient Reference List').first().json;

try {
  const content = claudeResponse.content[0].text;

  let cleanJson = content.trim();
  if (cleanJson.startsWith('```')) {
    cleanJson = cleanJson.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  }

  const parsed = JSON.parse(cleanJson);

  if (parsed.success === false) {
    return [{
      json: {
        valid: false,
        error: parsed.error || 'Could not parse recipe from the page content.',
        error_code: 'PARSE_FAILED'
      }
    }];
  }

  if (!parsed.recipe || !parsed.recipe.title) {
    return [{
      json: {
        valid: false,
        error: 'Parsed recipe is missing a title.',
        error_code: 'PARSE_FAILED'
      }
    }];
  }

  if (!parsed.ingredients || parsed.ingredients.length === 0) {
    return [{
      json: {
        valid: false,
        error: 'Parsed recipe has no ingredients.',
        error_code: 'PARSE_FAILED'
      }
    }];
  }

  if (!parsed.steps || parsed.steps.length === 0) {
    return [{
      json: {
        valid: false,
        error: 'Parsed recipe has no cooking steps.',
        error_code: 'PARSE_FAILED'
      }
    }];
  }

  parsed.recipe.servings = Math.max(1, parsed.recipe.servings || 2);

  if (!['easy', 'medium', 'hard'].includes(parsed.recipe.difficulty)) {
    parsed.recipe.difficulty = 'medium';
  }

  return [{
    json: {
      valid: true,
      parsed: parsed,
      household_id: buildData.household_id,
      source_url: buildData.source_url,
      source_text: buildData.recipe_text,
      source_type: 'url_import'
    }
  }];

} catch (e) {
  return [{
    json: {
      valid: false,
      error: 'Failed to parse AI response: ' + e.message,
      error_code: 'PARSE_FAILED'
    }
  }];
}

// Match ingredients and save to Supabase using axios
const axios = require('axios');

const recipe = $('Supabase: Save Recipe (Draft)').first().json;
const recipeId = Array.isArray(recipe) ? recipe[0].id : recipe.id;
const parsedData = $('Validate Claude Response').first().json;
const householdId = parsedData.household_id;
const ingredients = parsedData.parsed.ingredients;

const supabaseUrl = $env.PLATEFUL_SUPABASE_URL;
const serviceKey = $env.PLATEFUL_SUPABASE_SERVICE_KEY;

const headers = {
  'apikey': serviceKey,
  'Authorization': `Bearer ${serviceKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Fetch current household ingredients
const ingResponse = await axios.get(
  `${supabaseUrl}/rest/v1/ingredients?household_id=eq.${householdId}&is_archived=eq.false&select=id,name`,
  { headers }
);
const existingIngredients = ingResponse.data;

const ingLookup = {};
for (const ei of existingIngredients) {
  ingLookup[ei.name.toLowerCase()] = ei.id;
}

const recipeIngredients = [];
const unmatchedIngredients = [];

for (const ing of ingredients) {
  let ingredientId = null;
  const matchKey = (ing.matched_name || '').toLowerCase();
  const nameKey = ing.name.toLowerCase();

  if (matchKey && ingLookup[matchKey]) {
    ingredientId = ingLookup[matchKey];
  } else if (ingLookup[nameKey]) {
    ingredientId = ingLookup[nameKey];
  }

  if (!ingredientId) {
    const createResp = await axios.post(
      `${supabaseUrl}/rest/v1/ingredients`,
      { household_id: householdId, name: ing.name.toLowerCase(), category: 'other', default_unit: ing.unit || 'g' },
      { headers }
    );
    const created = createResp.data;
    ingredientId = Array.isArray(created) ? created[0].id : created.id;
    ingLookup[ing.name.toLowerCase()] = ingredientId;
    unmatchedIngredients.push(ing.name);
  }

  recipeIngredients.push({
    recipe_id: recipeId,
    ingredient_id: ingredientId,
    quantity: ing.quantity,
    unit: ing.unit,
    preparation: ing.preparation || null,
    is_optional: ing.is_optional || false,
    group_name: ing.group_name || null,
    sort_order: ing.sort_order || 0
  });
}

if (recipeIngredients.length > 0) {
  await axios.post(`${supabaseUrl}/rest/v1/recipe_ingredients`, recipeIngredients, { headers });
}

const steps = parsedData.parsed.steps.map(s => ({
  recipe_id: recipeId,
  step_number: s.step_number,
  instruction: s.instruction,
  duration_min: s.duration_min || null
}));

if (steps.length > 0) {
  await axios.post(`${supabaseUrl}/rest/v1/recipe_steps`, steps, { headers });
}

return [{
  json: {
    recipe_id: recipeId,
    parsed: parsedData.parsed,
    unmatched_ingredients: unmatchedIngredients,
    source_url: parsedData.source_url
  }
}];
